const sources = [
  {
    name: 'Tax Foundation - State Income Tax Rates',
    url: 'https://taxfoundation.org/data/all/state/state-income-tax-rates',
    key: 'tf_income_rates'
  },
  {
    name: 'Tax Foundation - State Sales Tax Rates',
    url: 'https://taxfoundation.org/data/all/state/state-and-local-sales-tax-rates',
    key: 'tf_sales_rates'
  },
  {
    name: 'Tax Foundation - State Corporate Tax Rates',
    url: 'https://taxfoundation.org/data/all/state/state-corporate-income-tax-rates-brackets',
    key: 'tf_corp_rates'
  }
];

const state = $getWorkflowStaticData('global');
if (!state.hashes) state.hashes = {};
if (!state.lastRun) state.lastRun = null;

const results = [];

for (const source of sources) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: source.url,
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; PaperworkLabs/1.0; data-monitor)',
        'Accept': 'text/html'
      },
      returnFullResponse: true,
      timeout: 15000
    });

    const body = typeof resp === 'string' ? resp : (resp.body || '');
    const text = String(body).replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 50000);

    // Simple hash: sum of char codes mod large prime
    let hash = 0;
    for (let i = 0; i < text.length; i++) {
      hash = ((hash << 5) - hash + text.charCodeAt(i)) | 0;
    }
    const hashStr = String(hash);

    const prevHash = state.hashes[source.key] || null;
    const changed = prevHash !== null && prevHash !== hashStr;

    results.push({
      name: source.name,
      url: source.url,
      key: source.key,
      status: 'ok',
      changed,
      isFirstRun: prevHash === null,
      contentLength: text.length
    });

    state.hashes[source.key] = hashStr;
  } catch (e) {
    results.push({
      name: source.name,
      url: source.url,
      key: source.key,
      status: 'error',
      error: String(e).slice(0, 200),
      changed: false,
      isFirstRun: false,
      contentLength: 0
    });
  }
}

state.lastRun = new Date().toISOString();

return [{ json: { results, lastRun: state.lastRun } }];

const { results, lastRun } = $input.first().json;
const botToken = $env.SLACK_BOT_TOKEN || '';
if (!botToken) return [];

const changed = results.filter(r => r.changed);
const errors = results.filter(r => r.status === 'error');
const firstRuns = results.filter(r => r.isFirstRun);

if (changed.length === 0 && errors.length === 0 && firstRuns.length === 0) {
  return [];
}

const parts = [];

if (changed.length > 0) {
  parts.push(':rotating_light: *Data Source Changes Detected*\n');
  parts.push('The following tax data sources have changed since last check:');
  for (const c of changed) {
    parts.push(`\u2022 *${c.name}*: <${c.url}|View page>`);
  }
  parts.push('\n:point_right: Run `pnpm extract:tax` and `pnpm review` in `packages/data` to update.');
}

if (errors.length > 0) {
  parts.push('\n:warning: *Source Fetch Errors*');
  for (const e of errors) {
    parts.push(`\u2022 ${e.name}: ${e.error}`);
  }
}

if (firstRuns.length > 0 && changed.length === 0) {
  parts.push(':white_check_mark: *Data Source Monitor — Baseline Set*\n');
  parts.push(`Monitoring ${results.length} source(s). Will alert on content changes.`);
}

const message = parts.join('\n');
return [{ json: { message, channel: 'C0ALVM4PAE7' } }];
